+    for left_index in 0..edges.len() {
+        if !keep[left_index] {
+            continue;
+        }
+        for right_index in (left_index + 1)..edges.len() {
+            if !keep[right_index] {
+                continue;
+            }
+
+            let left = &edges[left_index];
+            let right = &edges[right_index];
+
+            let is_reverse_pair = left.context == right.context
+                && left.from.primitive == right.from.primitive
+                && left.to.primitive == right.to.primitive
+                && left.from.acquire == right.from.acquire
+                && left.to.acquire == right.to.acquire
+                && left.from.class == right.to.class
+                && left.to.class == right.from.class;
