pub(super) fn rebind_lock_info(
    lock: &LockInfoArtifact,
    arg_bindings: &BTreeMap<usize, LockClassKey>,
) -> Option<LockInfoArtifact> {
    Some(LockInfoArtifact {
        class: rebind_lock_class(&lock.class, arg_bindings)?,
        primitive: lock.primitive.clone(),
        acquire: lock.acquire.clone(),
        guard_behavior: lock.guard_behavior.clone(),
    })
}

fn rebind_lock_class(
    lock_class: &LockClassKey,
    arg_bindings: &BTreeMap<usize, LockClassKey>,
) -> Option<LockClassKey> {
    let replacement = match &lock_class.root {
        LockRootKey::ReceiverArg { .. } => Some(arg_bindings.get(&1)?.clone()),
        LockRootKey::FnArg { index, .. } => Some(arg_bindings.get(index)?.clone()),
        _ => None,
    };

    if let Some(mut replacement) = replacement {
        replacement.projections.extend(
            lock_class
                .projections
                .iter()
                .skip(usize::from(has_redundant_boundary_deref(
                    &replacement.projections,
                    &lock_class.projections,
                )))
                .cloned(),
        );
        Some(replacement)
    } else {
        Some(lock_class.clone())
    }
}

fn has_redundant_boundary_deref(
    left: &[ProjectionKey],
    right: &[ProjectionKey],
) -> bool {
    matches!(
        (left.last(), right.first()),
        (Some(ProjectionKey::Deref { .. }), Some(ProjectionKey::Deref { .. }))
    )
}

fn deref_ty<'tcx>(ty: Ty<'tcx>) -> Option<Ty<'tcx>> {
    ty.builtin_deref(true).map(|value| value.ty)
}

fn field_identity<'tcx>(
    owner_ty: Ty<'tcx>,
    downcast_variant: Option<usize>,
    field: rustc_middle::mir::Field,
) -> (String, String) {
    let owner_ty_name = type_key(owner_ty);
    if let ty::Adt(adt, args) = owner_ty.kind() {
        let variant = downcast_variant.unwrap_or(0);
        if let Some(field_def) = adt.variant(variant).fields.get(field.index()) {
            let field_name = field_def.name.to_string();
            return (
                if args.is_empty() {
                    owner_ty_name
                } else {
                    tcx_name_without_args(adt)
                },
                field_name,
            );
        }
    }
    (owner_ty_name, format!("field{}", field.index()))
}

fn tcx_name_without_args<'tcx>(adt: AdtDef<'tcx>) -> String {
    adt.did().to_string()
}

fn variant_name_for_ty<'tcx>(enum_ty: Ty<'tcx>, variant_index: usize) -> String {
    let ty::Adt(adt, _) = enum_ty.kind() else {
        return format!("variant{variant_index}");
    };
    adt.variants()
        .get(variant_index)
        .map(|variant| variant.name.to_string())
        .unwrap_or_else(|| format!("variant{variant_index}"))
}

pub(super) fn span_to_location<'tcx>(
    tcx: TyCtxt<'tcx>,
    span: rustc_span::Span,
) -> Option<SourceLocation> {
    if span.is_dummy() {
        return None;
    }
    let source_map = tcx.sess.source_map();
    let location = source_map.lookup_char_pos(span.lo());
    Some(SourceLocation {
        file: location.file.name.to_string(),
        line: location.line,
        column: location.col_display + 1,
    })
}

pub(super) fn collect_callable_locals<'tcx>(body: &Body<'tcx>) -> BTreeMap<Local, DefId> {
    let mut callable_locals = BTreeMap::new();

    for (local, local_decl) in body.local_decls.iter_enumerated() {
        let Some(local_info) = &local_decl.local_info else {
            continue;
        };
        let rustc_middle::mir::ClearCrossCrate::Set(
            rustc_middle::mir::LocalInfo::StaticRef { def_id, .. },
        ) = local_info
        else {
            continue;
        };
        callable_locals.insert(local, *def_id);
    }

    for block_data in body.basic_blocks.iter() {
        for statement in &block_data.statements {
            let Some((place, rvalue)) = statement.kind.as_assign() else {
                continue;
            };
            let Some(local) = place.as_local() else {
                continue;
            };
            let Rvalue::Cast(_, operand, _) | Rvalue::Use(operand) = rvalue else {
                continue;
            };
            let Some((def_id, _)) = operand.const_fn_def() else {
                continue;
            };
            callable_locals.insert(local, def_id);
        }
    }

    callable_locals
}

pub(super) fn resolve_callback_operand<'tcx>(
    operand: Operand<'tcx>,
    callable_locals: &BTreeMap<Local, DefId>,
) -> Option<DefId> {
    if let Some((def_id, _)) = operand.const_fn_def() {
        return Some(def_id);
    }

    let Operand::Move(place) | Operand::Copy(place) = operand else {
        return None;
    };
    let local = place.as_local()?;
    callable_locals.get(&local).copied()
}

pub(super) fn format_local<'tcx>(body: &Body<'tcx>, local: Local) -> String {
    if local.as_usize() == 0 {
        return "return".into();
    }
    if local.as_usize() <= body.arg_count {
        return format!("arg{}", local.as_usize());
    }
    format!("_{}", local.as_usize())
}

