fn type_key<'tcx>(value_ty: Ty<'tcx>) -> String {
    peel_refs(value_ty).to_string()
}

fn classify_operand_origin<'tcx>(
    tcx: TyCtxt<'tcx>,
    current_def_id: DefId,
    body: &Body<'tcx>,
    state: &BlockState<'tcx>,
    operand: &Operand<'tcx>,
) -> LocalOriginKey {
    match operand {
        Operand::Copy(source) | Operand::Move(source) if source.as_local().is_some() => {
            LocalOriginKey::AliasOf(Box::new(place_root_key(
                tcx,
                current_def_id,
                body,
                state,
                source.local,
            )))
        }
        Operand::Constant(constant) => constant
            .check_static_ptr(tcx)
            .map(|def_id| {
                LocalOriginKey::AliasOf(Box::new(LockRootKey::Global {
                    def_path: tcx.def_path_str(def_id),
                }))
            })
            .unwrap_or(LocalOriginKey::Unknown),
        _ => LocalOriginKey::Unknown,
    }
}

fn transfer_guard_move<'tcx>(
    state: &mut BlockState<'tcx>,
    destination: Local,
    operand: &Operand<'tcx>,
) {
    let Operand::Move(source) = operand else {
        return;
    };
    let Some(source_local) = source.as_local() else {
        return;
    };
    let Some(lock) = state.guards.remove(&source_local) else {
        return;
    };

    state.guards.insert(destination, lock);

